import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

const TaskManager = () => {
  const { staffList, tasks, addTask } = useData();
  const [taskTitle, setTaskTitle] = useState('');
  const [assigneeId, setAssigneeId] = useState('');
  const [dates, setDates] = useState({ startDate: '', deadline: '' });
  // State mới cho hình thức kỷ luật
  const [discipline, setDiscipline] = useState('');

  const handleCreateTask = (e) => {
    e.preventDefault();
    if (!assigneeId) return alert("Vui lòng chọn nhân sự!");
    if (!dates.startDate || !dates.deadline) return alert("Vui lòng chọn ngày!");
    
    addTask({ 
      title: taskTitle, 
      assigneeId: parseInt(assigneeId),
      startDate: dates.startDate,
      deadline: dates.deadline,
      disciplinaryAction: discipline || 'Phạt hành chính 50.000đ' // Giá trị mặc định nếu để trống
    });
    
    // Reset form
    setTaskTitle('');
    setDates({ startDate: '', deadline: '' });
    setDiscipline('');
    alert("Đã giao việc thành công");
  };

  return (
    <div>
      <h2>Giao đầu việc & Thiết lập Kỷ luật</h2>
      <form onSubmit={handleCreateTask} style={{ marginBottom: '30px', padding: '20px', background: '#fff', border: '1px solid #ddd', borderRadius: '8px' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '15px' }}>
          {/* Tên công việc */}
          <div>
            <label>Tên đầu việc:</label>
            <input 
              placeholder="Nhập tên công việc..." 
              value={taskTitle} 
              onChange={e => setTaskTitle(e.target.value)} 
              required 
              style={{ padding: '8px', width: '95%', marginTop: '5px' }}
            />
          </div>

          {/* Chọn nhân sự */}
          <div>
            <label>Giao cho:</label>
            <select 
              value={assigneeId} 
              onChange={e => setAssigneeId(e.target.value)} 
              required 
              style={{ padding: '8px', width: '100%', marginTop: '5px' }}
            >
              <option value="">-- Chọn nhân sự --</option>
              {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>
          
          {/* Ngày tháng */}
          <div>
            <label>Ngày bắt đầu: </label>
            <input type="date" value={dates.startDate} onChange={e => setDates({...dates, startDate: e.target.value})} required style={{ display:'block', marginTop: '5px', padding: '5px'}} />
          </div>
          <div>
            <label>Deadline (Hạn chót): </label>
            <input type="date" value={dates.deadline} onChange={e => setDates({...dates, deadline: e.target.value})} required style={{ display:'block', marginTop: '5px', padding: '5px'}} />
          </div>

          {/* Hình thức kỷ luật */}
          <div style={{ gridColumn: 'span 2' }}>
            <label style={{ color: 'red', fontWeight: 'bold' }}>Hình thức kỷ luật (nếu không hoàn thành):</label>
            <input 
              placeholder="Ví dụ: Trừ 10% lương, Phạt 50k, Khiển trách..." 
              value={discipline} 
              onChange={e => setDiscipline(e.target.value)} 
              style={{ padding: '8px', width: '98%', marginTop: '5px', border: '1px solid red' }}
            />
          </div>
        </div>
        
        <button 
            type="submit" 
            style={{ background: '#003366', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '5px', fontWeight: 'bold', cursor: 'pointer' }}
          >
            KHỞI TẠO CÔNG VIỆC
        </button>
      </form>

      <h3>Danh sách công việc đã giao</h3>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {tasks.map(t => {
          const staff = staffList.find(s => s.id === t.assigneeId);
          return (
            <li key={t.id} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>
              <strong>{t.title}</strong> - Deadline: {t.deadline} <br/>
              <span style={{ fontSize: '0.9rem', color: '#666' }}>Nhân sự: {staff?.name} | Kỷ luật: {t.disciplinaryAction}</span>
            </li>
          );
        })}
      </ul>
    </div>
  );
};

export default TaskManager;
